### Pattern 2: Manual Offset Commit with Rebalance Listener

```java
public class ManualCommitConsumer {
    public static void main(String[] args) {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        props.put("group.id", "my-group");
        props.put("enable.auto.commit", false);
        props.put("key.deserializer", StringDeserializer.class);
        props.put("value.deserializer", StringDeserializer.class);

        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);

        ConsumerRebalanceListener listener = new ConsumerRebalanceListener() {
            @Override
            public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
                System.out.println("Revoking " + partitions);
                consumer.commitSync();
            }

            @Override
            public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
                System.out.println("Assigning " + partitions);
                // Offsets already handled by on-revoke commit
            }
        };

        consumer.subscribe(Arrays.asList("topic"), listener);

        try {
            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
                for (ConsumerRecord<String, String> record : records) {
                    process(record);
                }
                // Commit after processing batch
                consumer.commitSync();
            }
        } catch (WakeupException e) {
            System.out.println("Consumer shutting down");
        } finally {
            try {
                consumer.commitSync();
            } finally {
                consumer.close();
            }
        }
    }

    private static void process(ConsumerRecord<String, String> record) {
        System.out.println(record.value());
    }
}
```

### Pattern 3: Exactly-Once Semantics (Transactional)

```java
public class ExactlyOnceConsumer {
    private KafkaProducer<String, String> producer;
    private KafkaConsumer<String, String> consumer;

    public ExactlyOnceConsumer() {
        // Consumer configuration
        Properties consumerProps = new Properties();
        consumerProps.put("bootstrap.servers", "localhost:9092");
        consumerProps.put("group.id", "exactly-once-group");
        consumerProps.put("enable.auto.commit", false);
        consumerProps.put("isolation.level", "read_committed");
        consumerProps.put("key.deserializer", StringDeserializer.class);
        consumerProps.put("value.deserializer", StringDeserializer.class);

        this.consumer = new KafkaConsumer<>(consumerProps);

        // Producer configuration (transactional)
        Properties producerProps = new Properties();
        producerProps.put("bootstrap.servers", "localhost:9092");
        producerProps.put("transactional.id", "exactly-once-producer");
        producerProps.put("key.serializer", StringSerializer.class);
        producerProps.put("value.serializer", StringSerializer.class);

        this.producer = new KafkaProducer<>(producerProps);
        this.producer.initTransactions();
    }

    public void run() {
        consumer.subscribe(Arrays.asList("input-topic"));

        try {
            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));

                if (records.isEmpty()) {
                    continue;
                }

                producer.beginTransaction();
                try {
                    for (ConsumerRecord<String, String> record : records) {
                        String output = transform(record.value());
                        producer.send(new ProducerRecord<>("output-topic", record.key(), output));
                    }

                    // Commit consumer offset within producer transaction
                    Map<TopicPartition, OffsetAndMetadata> offsets = new HashMap<>();
                    for (TopicPartition partition : consumer.assignment()) {
                        long offset = consumer.position(partition);
                        offsets.put(partition, new OffsetAndMetadata(offset));
                    }
                    producer.sendOffsetsToTransaction(offsets, "my-group");

                    producer.commitTransaction();
                } catch (Exception e) {
                    producer.abortTransaction();
                    throw e;
                }
            }
        } finally {
            consumer.close();
            producer.close();
        }
    }

    private String transform(String value) {
        return value.toUpperCase();
    }
}
```

### Pattern 4: Multi-threaded Processing with Pause/Resume

```java
public class MultiThreadedConsumer {
    private final KafkaConsumer<String, String> consumer;
    private final ExecutorService workers;
    private final BlockingQueue<ConsumerRecord<String, String>> queue;
    private final int QUEUE_SIZE = 100;
    private volatile boolean running = true;

    public MultiThreadedConsumer() {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        props.put("group.id", "multi-threaded-group");
        props.put("enable.auto.commit", false);
        props.put("max.poll.records", "10");  // Small batches
        props.put("key.deserializer", StringDeserializer.class);
        props.put("value.deserializer", StringDeserializer.class);

        this.consumer = new KafkaConsumer<>(props);
        this.workers = Executors.newFixedThreadPool(10);
        this.queue = new LinkedBlockingQueue<>(QUEUE_SIZE);
    }

    public void run() {
        consumer.subscribe(Arrays.asList("topic"));

        // Worker threads
        for (int i = 0; i < 10; i++) {
            workers.submit(this::processWorker);
        }

        // Poll thread
        try {
            while (running) {
                // Check queue capacity
                if (queue.size() > QUEUE_SIZE - 10) {
                    // Pause all partitions to prevent overflow
                    consumer.pause(consumer.assignment());
                    System.out.println("Queue full, pausing");
                } else if (queue.size() < QUEUE_SIZE / 2) {
                    // Resume when queue has capacity
                    consumer.resume(consumer.assignment());
                    System.out.println("Queue has capacity, resuming");
                }

                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));

                for (ConsumerRecord<String, String> record : records) {
                    try {
                        queue.put(record);
                    } catch (InterruptedException e) {
                        Thread.currentThread().interrupt();
                        break;
                    }
                }

                // Periodically commit processed offsets
                consumer.commitAsync();
            }
        } finally {
            consumer.close();
            workers.shutdown();
        }
    }

    private void processWorker() {
        while (running) {
            try {
                ConsumerRecord<String, String> record = queue.take();
                process(record);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    private void process(ConsumerRecord<String, String> record) {
        // Simulate processing
        System.out.println("Processing: " + record.value());
    }
}
```

### Pattern 5: Standalone Consumer (Manual Assignment)

```java
public class StandaloneConsumer {
    public static void main(String[] args) {
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        // Note: No group.id for standalone mode
        props.put("enable.auto.commit", false);
        props.put("key.deserializer", StringDeserializer.class);
        props.put("value.deserializer", StringDeserializer.class);

        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);

        // Manually assign partitions
        TopicPartition partition0 = new TopicPartition("topic", 0);
        TopicPartition partition1 = new TopicPartition("topic", 1);
        consumer.assign(Arrays.asList(partition0, partition1));

        // Seek to specific positions
        consumer.seek(partition0, 0);      // Start from beginning
        consumer.seek(partition1, 1000);   // Start from offset 1000

        try {
            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));

                // Process by partition
                for (TopicPartition partition : records.partitions()) {
                    for (ConsumerRecord<String, String> record : records.records(partition)) {
                        System.out.printf(
                            "Partition %d: offset=%d, value=%s%n",
                            partition.partition(), record.offset(), record.value()
                        );
                    }
                }

                // Manual commit
                consumer.commitSync();
            }
        } finally {
            consumer.close();
        }
    }
}
